1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Empty / processing fee ===
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result.results[0]).toEqual({ premium: 5 });
12	  });
13	
14	  // === Base premiums per main item type ===
15	  it.todo("single plain sword → premium 105 G (100 base + 5 fee)");
16	  it.todo("single plain amulet → premium 65 G (60 base + 5 fee)");
17	  it.todo("single plain staff → premium 85 G (80 base + 5 fee)");
18	  it.todo("single plain potion → premium 45 G (40 base + 5 fee)");
19	
20	  // === Components ===
21	  it.todo("2 runes → 55 G premium (2×25 base + 5 fee)");
22	  it.todo("3 runes → 65 G premium (block: 60 base + 5 fee)");
23	  it.todo("4 runes → 105 G premium (no block — block requires exactly 3)");
24	  it.todo("7 runes → 180 G premium (175 base + 5 fee)");
25	
26	  // === "Alike" components ===
27	  it.todo("2 runes + 1 moonstone → 80 G premium (75 base + 5 fee, no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 125 G premium (two separate blocks: 60+60 + 5 fee)");
29	
30	  // === Item-specific modifiers ===
31	  it.todo("cursed sword (newcomer, no first-insurance) — curse surcharge is 50% of cursed item's base premium");
32	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (30%)");
33	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
34	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
35	
36	  // === Policy-wide modifiers ===
37	  it.todo("customer with exactly 2 years → loyalty discount applies (20%)");
38	  it.todo("first insurance carries 10% initial assessment surcharge");
39	  it.todo("customer's second contract gets 15% follow-up discount");
40	
41	  // === Modifier scope on multi-item policies ===
42	  it.todo("cursed sword + plain amulet → policy 215 G (160 base + 50 curse + 5 fee)");
43	
44	  // === Integration: newcomer with cursed sword ===
45	  it.todo("newcomer (0 years) cursed sword (enchantment 3) → premium 165 G");
46	
47	  // === Integration: long-standing customer's second contract ===
48	  it.todo("3-year customer, second quote, cursed sword (enchantment 7) → premium 160 G");
49	
50	  // === Rounding ===
51	  it.todo("premium yielding 197.5 G → final 198 G (rounded up)");
52	
53	  // === Claim: standard reimbursement ===
54	  it.todo("regular sword (steel, enchantment 3), damage 500 G → payout 400 G");
55	  it.todo("rune damage 200 G → payout 100 G (no special clauses)");
56	
57	  // === Claim: enchantment threshold ===
58	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
59	
60	  // === Claim: dragon material ===
61	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full reimbursement minus deductible)");
62	
63	  // === Claim: both clauses ===
64	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G (50% rule wins, then deductible)");
65	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G → payout 400 G (high-enchant then deductible)");
66	
67	  // === Claim: deductible per damage event ===
68	  it.todo("dragon attack damages insured sword 500 G + amulet 300 G → payout 600 G (deductible per item)");
69	
70	  // === Multiple items of same type ===
71	  it.todo("policy covers two swords → insurance sum 2000 G, cap 4000 G");
72	  it.todo("policy covers two swords, dragon attack damages both → each damage has its own deductible");
73	  it.todo("damages array has more entries of a type than the policy covers → CLI exits non-zero");
74	
75	  // === Cap exhaustion ===
76	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
77	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
78	  it.todo("sword + 3 runes block → insurance sum 1750 G (block discount affects premium only)");
79	  it.todo("sword cap 2000 G, two 1500 G claims → first payout 1400 G remaining 600 G; second payout 600 G remaining 0 G");
80	
81	  // === Payout rounding ===
82	  it.todo("payout calc yielding 350.5 G → final payout 350 G (rounded down)");
83	
84	  // === Edge cases / errors ===
85	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results to stdout");
86	  it.todo("claim references damage for item not in policy → CLI exits non-zero");
87	  it.todo("claim damage entry with negative amount → CLI exits non-zero");
88	});
